'use strict';

const express = require('express');

const setHeaders = (setter) => {
  setter('X-Content-Type-Options', 'nosniff');
  setter('X-Frame-Options', 'DENY');
  setter('Referrer-Policy', 'no-referrer');
  setter('X-Permitted-Cross-Domain-Policies', 'none');
  setter('X-DNS-Prefetch-Control', 'off');
  setter('Permissions-Policy', 'camera=(), microphone=(), geolocation=()');
  setter('Cross-Origin-Opener-Policy', 'same-origin');
  setter('Cross-Origin-Resource-Policy', 'same-origin');
  setter('X-XSS-Protection', '0');
  if (process.env.FORTRESS_HSTS === 'true') {
    setter('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  }
};

function expressFortress(req, res, next) {
  setHeaders((name, value) => {
    if (typeof res.set === 'function') {
      res.set(name, value);
    } else if (typeof res.setHeader === 'function') {
      res.setHeader(name, value);
    }
  });
  next();
}

async function koaFortress(ctx, next) {
  setHeaders((name, value) => {
    if (ctx && typeof ctx.set === 'function') {
      ctx.set(name, value);
    }
  });
  await next();
}

const router = express.Router();

router.get('/status/fo', (req, res) => {
  res.status(200).json({ status: 'ok', fortress: true });
});

module.exports = { expressFortress, koaFortress, router };
